+RUN apk add --no-cache curl
+RUN git clone https://example.com/repo.git && git reset --hard HEAD~1
+COPY . /app
+CMD ["./app"]
+"#,
+    )
+    .unwrap();
+
+    let output = run_dcg_scan(&[
+        "--paths",
+        dir.path().to_str().unwrap(),
+        "--format",
+        "json",
+    ]);
+
